export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const live = new Set(liveCells.map(([x, y]) => key(x, y)));
  const countNeighbors = (x: number, y: number) => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (live.has(key(x + dx, y + dy))) count++;
      }
    }
    return count;
  };
  return liveCells.filter(([x, y]) => {
    const n = countNeighbors(x, y);
    return n === 2 || n === 3;
  });
}

